                          ? "border-rose-500/25 bg-rose-500/12 text-rose-200"
                          : "border-amber-500/25 bg-amber-500/12 text-amber-200"
                    )}
                  >
                    {item.bias}
                  </Badge>
                </div>
                <p className="mt-1 text-xs text-muted-foreground">
                  {formatNumber(item.todayChange)}% · {item.gapStatus.replace(/-/g, " ")} ·{" "}
