        : copy(language, "Earnings taslagi kaydediliyor", "Saving earnings draft")
    );
    setAdminError("");

    try {
      const reportToSave: WeeklyReportRecord = {
        ...sourceReport,
        status,
        publishedAt:
          status === "published"
            ? sourceReport.publishedAt || new Date().toISOString()
            : undefined,
      };

      const response = await fetch("/api/admin/reports/weekly", {
        method: "POST",
        credentials: "include",
        headers: {
          "Content-Type": "application/json",
          ...buildAdminHeaders(),
        },
        body: JSON.stringify({ report: reportToSave }),
