const SESSION_TTL_SECONDS = Math.floor(ONE_YEAR_MS / 1000);
const DEFAULT_SUBSCRIPTION_DAYS = 30;
const DEFAULT_APP_ACCESS_MODE: AppAccessMode = "managed";
const PUBLIC_ACCESS_USER = {
