  ["weekly-report-2026-06-08", "2026-06-06T08:30:00.000Z"],
]);

function isLegacyWeeklySeedReport(report: WeeklyReportRecord) {
  const publishedAt = LEGACY_WEEKLY_SEED_SIGNATURES.get(report.id);
